  "yaku.tsumo.desc": { es: "Ganar robando del muro con la mano cerrada.", en: "Win by self-draw with a closed hand.", ja: "門前のまま自分のツモで和了する。" },
  "yaku.haitei.desc": { es: "Tsumo con la última ficha del muro.", en: "Self-draw win on the last tile of the wall.", ja: "最後のツモ牌で和了する。" },
  "yaku.houtei.desc": { es: "Ron sobre el último descarte de la mano.", en: "Ron on the final discard of the hand.", ja: "最後の捨て牌でロン和了する。" },
  "yaku.rinshan.desc": { es: "Ganar con la ficha extra robada tras declarar un kan.", en: "Win on the replacement tile drawn after a kan.", ja: "カンの後に引いた嶺上牌で和了する。" },
  "yaku.chankan.desc": { es: "Ron sobre la ficha con la que un rival amplía su pon a kan.", en: "Ron on the tile a rival adds to upgrade a pon into a kan.", ja: "加槓された牌でロン和了する。" },
  "yaku.tenhou.desc": { es: "El oya gana con su mano inicial, antes de cualquier descarte.", en: "The dealer wins with the starting hand, before any discard.", ja: "親が配牌のまま和了する。" },
  "yaku.chiihou.desc": { es: "Un no-oya gana con su primer robo, sin llamadas previas.", en: "A non-dealer wins on the first draw, before any call.", ja: "子が鳴きのない第一ツモで和了する。" },
  "yaku.pinfu.desc": { es: "Cuatro corridas y pareja sin valor, ganando con espera de dos lados.", en: "Four runs and a valueless pair, won on a two-sided wait.", ja: "順子4組と役牌以外の雀頭、両面待ちで和了する。" },
  "yaku.tanyao.desc": { es: "Solo fichas del 2 al 8: sin terminales ni honores.", en: "Only tiles 2 through 8: no terminals or honors.", ja: "一九字牌を使わずに揃える。" },
  "yaku.iipeiko.desc": { es: "Dos corridas idénticas; solo con mano cerrada.", en: "Two identical runs; closed hand only.", ja: "同じ順子を2組作る。門前のみ。" },
  "yaku.ryanpeiko.desc": { es: "Dos pares de corridas idénticas; solo con mano cerrada.", en: "Two pairs of identical runs; closed hand only.", ja: "一盃口を二つ作る。門前のみ。" },
  "yaku.yakuhai-haku.desc": { es: "Trío o kan del dragón blanco.", en: "A triplet or kan of the white dragon.", ja: "白の刻子か槓子を作る。" },
  "yaku.yakuhai-hatsu.desc": { es: "Trío o kan del dragón verde.", en: "A triplet or kan of the green dragon.", ja: "發の刻子か槓子を作る。" },
  "yaku.yakuhai-chun.desc": { es: "Trío o kan del dragón rojo.", en: "A triplet or kan of the red dragon.", ja: "中の刻子か槓子を作る。" },
  "yaku.yakuhai-seat.desc": { es: "Trío o kan de tu viento de asiento.", en: "A triplet or kan of your seat wind.", ja: "自風牌の刻子か槓子を作る。" },
  "yaku.yakuhai-round.desc": { es: "Trío o kan del viento de la ronda.", en: "A triplet or kan of the round wind.", ja: "場風牌の刻子か槓子を作る。" },
  "yaku.sanshoku.desc": { es: "La misma corrida en los tres palos.", en: "The same run in all three suits.", ja: "三色で同じ順子を作る。" },
  "yaku.sanshoku-doukou.desc": { es: "El mismo trío en los tres palos.", en: "The same triplet in all three suits.", ja: "三色で同じ刻子を作る。" },
  "yaku.ittsu.desc": { es: "Corridas 123, 456 y 789 del mismo palo.", en: "Runs 123, 456 and 789 in a single suit.", ja: "同じ色で123・456・789を揃える。" },
  "yaku.toitoi.desc": { es: "Cuatro tríos o kans más la pareja.", en: "Four triplets or kans plus the pair.", ja: "刻子と槓子だけで4組作る。" },
  "yaku.sanankou.desc": { es: "Tres tríos cerrados (no completados por ron).", en: "Three concealed triplets (not completed by ron).", ja: "暗刻を3組作る。" },
  "yaku.sankantsu.desc": { es: "Tres kans declarados.", en: "Three declared kans.", ja: "槓子を3組作る。" },
  "yaku.honroutou.desc": { es: "Solo terminales y honores, en tríos o pares.", en: "Terminals and honors only, in triplets or pairs.", ja: "一九字牌だけで刻子と雀頭を作る。" },
  "yaku.junchan.desc": { es: "Cada bloque contiene un 1 o un 9; sin honores.", en: "Every block contains a 1 or a 9; no honors.", ja: "全ての面子と雀頭に一九牌を含む。字牌なし。" },
  "yaku.chanta.desc": { es: "Cada bloque contiene terminal u honor.", en: "Every block contains a terminal or an honor.", ja: "全ての面子と雀頭に一九字牌を含む。" },
  "yaku.shousangen.desc": { es: "Tríos de dos dragones y pareja del tercero.", en: "Triplets of two dragons and a pair of the third.", ja: "三元牌の刻子2組と雀頭を作る。" },
  "yaku.honitsu.desc": { es: "Un solo palo más honores.", en: "One suit plus honor tiles.", ja: "一色の数牌と字牌だけで揃える。" },
  "yaku.chinitsu.desc": { es: "Un solo palo, sin honores.", en: "A single suit with no honors.", ja: "一色の数牌だけで揃える。" },
  "yaku.chiitoi.desc": { es: "Siete pares distintos; solo con mano cerrada.", en: "Seven distinct pairs; closed hand only.", ja: "七種の対子で揃える。門前のみ。" },
  "yaku.kokushi.desc": { es: "Una de cada terminal y honor, más una repetida.", en: "One of each terminal and honor, plus one duplicate.", ja: "一九字牌13種を全て集めて和了する。" },
  "yaku.suuankou.desc": { es: "Cuatro tríos cerrados.", en: "Four concealed triplets.", ja: "暗刻を4組作る。" },
  "yaku.daisangen.desc": { es: "Tríos de los tres dragones.", en: "Triplets of all three dragons.", ja: "三元牌の刻子を3組作る。" },
