  "yaku.ryuuiisou.desc": { es: "Solo fichas verdes: 2, 3, 4, 6 y 8 de bambú y hatsu.", en: "Green tiles only: 2, 3, 4, 6, 8 of bamboo and hatsu.", ja: "緑色の牌だけで揃える。" },
  "yaku.suukantsu.desc": { es: "Cuatro kans declarados.", en: "Four declared kans.", ja: "槓子を4組作る。" },
  "yaku.chuuren.desc": { es: "1112345678999 del mismo palo más una ficha extra.", en: "1112345678999 in one suit plus any one extra tile.", ja: "同じ色で1112345678999ともう1枚。" },
  "yaku.dora.desc": { es: "Cada dora señalada por el indicador suma 1 han.", en: "Each dora shown by the indicator adds 1 han.", ja: "ドラ1枚ごとに1翻加算。" },
  "yaku.ura.desc": { es: "Dora oculta bajo el indicador; solo para quien gana con riichi.", en: "Hidden dora under the indicator; riichi winners only.", ja: "リーチ和了の時だけ見られる裏のドラ。" },
